import json
from collections import deque
from functools import lru_cache

ACTION_ORDER = [f'D{i}' for i in range(4)] + [f'L{i}' for i in range(4)] + [f'R{i}' for i in range(4)] + [f'U{i}' for i in range(4)]
ZERO = bytes([0] * 16)
BOARD_OPS = {"set", "add", "shift_row", "shift_col", "rotate", "swap", "copy"}

def action_orientation(action):
    return 'row' if action[0] in 'LR' else 'col'

def apply_action(state, action, mod=4, size=4):
    board = bytearray(state)
    kind = action[0]
    idx = int(action[1])
    if kind in 'LR':
        start = idx * size
        row = list(board[start:start+size])
        if kind == 'R':
            row = [ (v + 1) % mod for v in row ]
            shift = 1 % size
            row = row[-shift:] + row[:-shift]
        else:
            shift = 1 % size
            row = row[shift:] + row[:shift]
            row = [ (v - 1) % mod for v in row ]
        board[start:start+size] = bytes(row)
    else:
        col = [board[idx + r * size] for r in range(size)]
        if kind == 'D':
            col = [ (v + 1) % mod for v in col ]
            shift = 1 % size
            col = col[-shift:] + col[:-shift]
        else:
            shift = 1 % size
            col = col[shift:] + col[:shift]
            col = [ (v - 1) % mod for v in col ]
        for r, v in enumerate(col):
            board[idx + r * size] = v
    return bytes(board)

# precompute distances
DIST = {ZERO: 0}
q = deque([ZERO])
while q:
    state = q.popleft()
    depth = DIST[state]
    if depth == 5:
        continue
    for action in ACTION_ORDER:
        nxt = apply_action(state, action)
        if nxt not in DIST:
            DIST[nxt] = depth + 1
            q.append(nxt)
print('states', len(DIST))

def replay(chapter, mod=4, size=4):
    events = chapter['events']
    events_by_id = {event['id']: event for event in events}
    canceled = set()
    active = {}
    for event in sorted(events, key=lambda e: e['id'], reverse=True):
        eid = event['id']
        is_active = eid not in canceled
        active[eid] = is_active
        if is_active and event['op'] == 'cancel':
            canceled.add(event['target'])
    amendments = {}
    for event in sorted(events, key=lambda e: e['id'], reverse=True):
        if not active[event['id']] or event['op'] != 'amend':
            continue
        target = event['target']
        if target not in events_by_id or not active.get(target, False):
            continue
        key = (target, event['field'])
        if key not in amendments:
            amendments[key] = event['value']
    board_events = []
    for event in events:
        if not active[event['id']] or event['op'] not in BOARD_OPS:
            continue
        effective = dict(event)
        for (target, field), value in amendments.items():
            if target == event['id']:
                effective[field] = value
        board_events.append(effective)
    board_events.sort(key=lambda e: (e['at'], e['id']))
    board = [[0] * size for _ in range(size)]
    for event in board_events:
        op = event['op']
        if op == 'set':
            board[event['row']][event['col']] = event['value'] % mod
        elif op == 'add':
            delta = event['delta'] % mod
            for r in range(event['top'], event['bottom'] + 1):
                for c in range(event['left'], event['right'] + 1):
                    board[r][c] = (board[r][c] + delta) % mod
        elif op == 'shift_row':
            r = event['row']
            amt = event['amount'] % size
            row = board[r][:]
            board[r] = row[-amt:] + row[:-amt] if amt else row
        elif op == 'shift_col':
            c = event['col']
            amt = event['amount'] % size
            col = [board[r][c] for r in range(size)]
            if amt:
                col = col[-amt:] + col[:-amt]
            for r, v in enumerate(col):
                board[r][c] = v
        elif op == 'rotate':
            top = event['top']
            left = event['left']
            sq = event['size']
            turns = event['turns'] % 4
            if turns:
                block = [row[left:left+sq] for row in board[top:top+sq]]
                for _ in range(turns):
                    block = [list(row) for row in zip(*block[::-1])]
                for r in range(sq):
                    board[top+r][left:left+sq] = block[r]
        elif op == 'swap':
            a = event['first'] % mod
            b = event['second'] % mod
            for r in range(size):
                for c in range(size):
                    if board[r][c] == a:
                        board[r][c] = b
                    elif board[r][c] == b:
                        board[r][c] = a
        elif op == 'copy':
            snap = [row[:] for row in board]
            h = event['height']
            w = event['width']
            for dr in range(h):
                for dc in range(w):
                    board[event['target_top'] + dr][event['target_left'] + dc] = snap[event['source_top'] + dr][event['source_left'] + dc]
    return bytes(v % mod for row in board for v in row)


def solve_state(state):
    d = DIST[state]
    @lru_cache(None)
    def best_changes(cur, prev):
        rem = DIST[cur]
        if rem == 0:
            return 0
        prev_orient = None if prev == 2 else ('row' if prev == 0 else 'col')
        best = 10**9
        for action in ACTION_ORDER:
            nxt = apply_action(cur, action)
            if DIST.get(nxt) != rem - 1:
                continue
            orient = action_orientation(action)
            penalty = 0 if prev_orient is None or prev_orient == orient else 1
            code = 0 if orient == 'row' else 1
            cand = penalty + best_changes(nxt, code)
            if cand < best:
                best = cand
        return best
    seq = []
    cur = state
    prev_orient = None
    prev_code = 2
    while DIST[cur] > 0:
        rem = DIST[cur]
        target = best_changes(cur, prev_code)
        for action in ACTION_ORDER:
            nxt = apply_action(cur, action)
            if DIST.get(nxt) != rem - 1:
                continue
            orient = action_orientation(action)
            penalty = 0 if prev_orient is None or prev_orient == orient else 1
            code = 0 if orient == 'row' else 1
            cand = penalty + best_changes(nxt, code)
            if cand == target:
                seq.append(action)
                cur = nxt
                prev_orient = orient
                prev_code = code
                break
        else:
            raise RuntimeError('no step')
    return seq

with open('/app/examples.json') as f:
    examples = json.load(f)['cases']
for i, case in enumerate(examples, 1):
    got = []
    for chapter in case['input']['chapters']:
        state = replay(chapter, case['input']['modulus'], case['input']['size'])
        got.append(solve_state(state))
    print(i, got, got == case['output']['solutions'])
